const msg = $json;

// Body extraction
let body = (msg.text || '').trim();

if (!body && msg.html) {
  body = msg.html
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<\/p>/gi, '\n')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .trim();
}

body = body.replace(/\r\n/g, '\n').trim();

// Sender
const fromObj = msg.from?.value?.[0] || {};
const fromEmail = (fromObj.address || '').toLowerCase();
const fromName = fromObj.name || '';
const fromDomain = fromEmail.includes('@') ? fromEmail.split('@')[1] : '';

// Header signals
const headers = msg.headers || {};
const headersText = Object.values(headers).join('\n').toLowerCase();

const hasListUnsubscribe =
  headersText.includes('list-unsubscribe') ||
  Boolean(headers['list-unsubscribe']) ||
  Boolean(headers['List-Unsubscribe']);

const isAutoSubmitted = headersText.includes('auto-submitted');
const isBulk =
  headersText.includes('precedence: bulk') ||
  headersText.includes('precedence: list') ||
  headersText.includes('x-autoreply') ||
  headersText.includes('x-auto-response-suppress');

const isNoReply = fromEmail.includes('no-reply') || fromEmail.includes('noreply');

const likelyMarketing =
  hasListUnsubscribe ||
  isBulk ||
  headersText.includes('list-id') ||
  headersText.includes('unsubscribe');

// Return as a single object (not an array)
return {
  id: msg.id,
  threadId: msg.threadId,
  subject: msg.subject || '',
  snippet: msg.snippet || '',
  date: msg.date || '',
  fromName,
  fromEmail,
  fromDomain,
  to: msg.to?.text || '',
  bodyText: body,
  signals: {
    isNoReply,
    hasListUnsubscribe,
    isAutoSubmitted,
    isBulk,
    likelyMarketing,
  },
};

const e = $json;

const domain = (e.fromDomain || '').toLowerCase();
const fromEmail = (e.fromEmail || '').toLowerCase();
const subject = (e.subject || '').toLowerCase();
const body = (e.bodyText || '').toLowerCase();

const domainMatch = (list) => list.some(d => domain === d || domain.endsWith('.' + d));
const containsAny = (list) => list.some(k => subject.includes(k) || body.includes(k));

// --- domains ---
const securityDomains = [
  'google.com', 'accounts.google.com',
  'facebookmail.com', 'facebook.com',
  'x.com', 'twitter.com',
  'youtube.com', 'accounts.youtube.com',
  'microsoft.com', 'account.microsoft.com',
  'apple.com', 'id.apple.com'
];

const socialDomains = [
  'facebookmail.com', 'facebook.com',
  'x.com', 'twitter.com',
  'youtube.com', 'accounts.youtube.com',
  'instagram.com', 'linkedin.com', 'tiktok.com', 'pinterest.com'
];

// --- keywords ---
const securityKw = [
  'security alert', 'suspicious', 'sign-in', 'signin', 'new login',
  'unusual activity', 'password changed', 'password reset',
  '2-step', '2fa', 'verification code', 'otp',
  'confirm your identity', 'recover', 'reset your password'
];

const socialKw = [
  'new follower', 'new like', 'commented', 'mentioned you',
  'tagged you', 'notification', 'digest', 'weekly update'
];

const promoKw = [
  'sale', 'discount', 'offer', 'limited time', 'deal',
  'newsletter', 'promotion', 'promo', 'coupon', 'save ',
  'new arrivals', 'free shipping', 'unsubscribe'
];

// --- heuristics ---
const isSecurityDomain = domainMatch(securityDomains);
const isSocialDomain = domainMatch(socialDomains);

const isLikelyPromoSender =
  e.signals?.likelyMarketing ||
  e.signals?.hasListUnsubscribe ||
  e.signals?.isBulk ||
  e.signals?.isNoReply ||
  fromEmail.includes('marketing') ||
  fromEmail.includes('newsletter') ||
  fromEmail.includes('offers') ||
  fromEmail.includes('promo');

let ruleCategory = null;
let ruleReason = '';

// 1) SECURITY (highest priority)
if (isSecurityDomain && containsAny(securityKw)) {
  ruleCategory = 'security';
  ruleReason = 'Security domain + security keywords';

// 2) SOCIAL (non-security)
} else if (isSocialDomain && !containsAny(securityKw) &&
  (containsAny(socialKw) || e.signals?.isNoReply || e.signals?.isBulk || e.signals?.hasListUnsubscribe)) {
  ruleCategory = 'social';
  ruleReason = 'Social domain + notification signals';

// 3) PROMOTIONS (marketing/newsletters)
} else if (!containsAny(securityKw) && (containsAny(promoKw) || isLikelyPromoSender)) {
  ruleCategory = 'promotions';
  ruleReason = 'Marketing/promotional signals detected';

}

if (ruleCategory==null) {
  ruleCategory = 'uncertain'
  ruleReason = 'No rule match';
}

return {
  ...e,
  rule: {
    category: ruleCategory, // 'security' | 'social' | 'promotions' | null
    reason: ruleReason
  }
};

