const item = $input.first().json;
const rawText = item?.content?.parts?.[0]?.text ?? "";

// Allowed categories only
const ALLOWED = new Set(["security", "social", "promotions", "reply"]);

// Fallback when parsing fails or category is invalid
const FALLBACK_CATEGORY = "reply";
const FALLBACK_CONFIDENCE = 0.2; // low confidence

let parsed = null;

// 1) Try direct JSON parse
try {
  parsed = JSON.parse(rawText);
} catch {
  // 2) Try extracting a JSON object substring
  const start = rawText.indexOf("{");
  const end = rawText.lastIndexOf("}");
  if (start >= 0 && end > start) {
    try {
      parsed = JSON.parse(rawText.slice(start, end + 1));
    } catch {
      parsed = null;
    }
  }
}

// Normalize + validate
const category = String(parsed?.category ?? "").toLowerCase().trim();
const confidence = Number(parsed?.confidence);
const reason = String(parsed?.reason ?? "").trim();

const safeCategory = ALLOWED.has(category) ? category : FALLBACK_CATEGORY;

// Confidence: if invalid, use fallback confidence. Clamp 0..1
let safeConfidence = Number.isFinite(confidence) ? confidence : FALLBACK_CONFIDENCE;
safeConfidence = Math.max(0, Math.min(1, safeConfidence));

// If we had to fallback, force low confidence
if (!ALLOWED.has(category)) {
  safeConfidence = FALLBACK_CONFIDENCE;
}

const safeReason =
  reason ||
  (parsed
    ? "Missing/empty reason."
    : "Classifier output was not valid JSON; used fallback category reply.");

return [
  {
    json: {
      category: safeCategory,
      confidence: safeConfidence,
      reason: safeReason,
    },
  },
];

const item = $input.first().json;

// Normalize category text
let classifierCategory = String(item.category)
  .toLowerCase()
  .trim();

// Normalize common variants/synonyms
if (["promotion", "promotions"].includes(classifierCategory)) {
  classifierCategory = "promotions";
}
if (["secure", "security"].includes(classifierCategory)) {
  classifierCategory = "security";
}

return [
  {
    json: {
      ...item,
      classifierCategory,
    },
  },
];

const THRESHOLD = 60; // readability threshold (0..100)

// The tool input comes in as: $json.query
const raw = (typeof $json.query === 'string') ? $json.query : '';

function stripHtml(input = "") {
  return String(input)
    .replace(/<style[\s\S]*?<\/style>/gi, " ")
    .replace(/<script[\s\S]*?<\/script>/gi, " ")
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;|&#160;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeText(input = "") {
  return stripHtml(input)
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/\s+/g, " ")
    .trim();
}

function countSentences(text = "") {
  const t = text.trim();
  if (!t) return 0;
  const matches = t.match(/[.!?]+(?=\s|$)/g);
  const n = matches ? matches.length : 0;
  return Math.max(1, n);
}

function tokenizeWords(text = "") {
  const cleaned = text
    .toLowerCase()
    .replace(/[^a-z0-9'\s-]/g, " ")
    .replace(/[-]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!cleaned) return [];
  return cleaned.split(" ").filter(Boolean);
}

function countSyllablesInWord(word = "") {
  let w = String(word).toLowerCase().replace(/[^a-z]/g, "");
  if (!w) return 0;
  if (w.length <= 3) return 1;

  if (w.endsWith("e")) {
    if (!(w.endsWith("le") && w.length > 2 && !/[aeiouy]/.test(w[w.length - 3]))) {
      w = w.slice(0, -1);
    }
  }

  const groups = w.match(/[aeiouy]+/g);
  let count = groups ? groups.length : 0;

  if (w.endsWith("ed") && !/(ted|ded)$/.test(w)) count -= 1;
  if (w.endsWith("es") && !/(ses|xes|zes|ches|shes)$/.test(w)) count -= 1;

  return Math.max(1, count);
}

function fleschReadingEase(sentences, words, syllables) {
  if (!sentences || !words) return 0;
  const score =
    206.835 -
    1.015 * (words / sentences) -
    84.6 * (syllables / words);
  return Math.max(0, Math.min(100, score));
}

function gradeHint(score) {
  if (score >= 90) return "Very easy";
  if (score >= 80) return "Easy";
  if (score >= 70) return "Fairly easy";
  if (score >= 60) return "Standard";
  if (score >= 50) return "Fairly difficult";
  if (score >= 30) return "Difficult";
  return "Very difficult";
}

const text = normalizeText(raw);

if (!text) {
  return JSON.stringify({
    score: 0,
    threshold: THRESHOLD,
    needs_improvement: true,
    grade_hint: "No text",
    stats: {
      sentences: 0,
      words: 0,
      syllables: 0,
      avg_words_per_sentence: 0,
      avg_syllables_per_word: 0
    }
  });
}

const sentences = countSentences(text);
const wordsArr = tokenizeWords(text);
const words = wordsArr.length;

let syllables = 0;
for (const w of wordsArr) syllables += countSyllablesInWord(w);

const score = fleschReadingEase(sentences, words, syllables);

return JSON.stringify({
  score: Number(score.toFixed(2)),
  threshold: THRESHOLD,
  needs_improvement: score < THRESHOLD,
  grade_hint: gradeHint(score),
  stats: {
    sentences,
    words,
    syllables,
    avg_words_per_sentence: Number((words / sentences).toFixed(2)),
    avg_syllables_per_word: Number((syllables / words).toFixed(3))
  }
});

const item = $input.first().json;
const o = item.output || {};

const s = (v) => (typeof v === 'string' ? v : '');
const senderName = s(item.email?.fromName).trim();

// ---------- 1) Salutation rule ----------
const salutation = senderName ? `Dear ${senderName},` : 'Hello,';

// ---------- 2) Closing rule (sanitize) ----------
const allowedClosings = new Set([
  'Best regards,',
  'Warm regards,',
  'Sincerely,',
  'Kind regards,',
  'Thanks,',
]);

let closing = s(o.closing).trim();
if (!allowedClosings.has(closing)) closing = 'Best regards,';

// ---------- 3) Body ----------
const draftBody = s(o.draft).trim();

// ---------- 4) Signature HTML ----------
const signatureHtml = `
<div style="margin-top:10px">
  <div style="margin-top:10px">
    <img src="https://drive.google.com/uc?export=view&id=1SqM5LGJXu37ICN_rLxe7gSpdc3IZwPCn" alt="Signature" width="220" />
  </div>
  <div><strong>Md. Rifat Aknda</strong></div>
  <div>Student, ULAB</div>
  <div><a href="mailto:rifat.aknda.cse@ulab.edu.bd">rifat.aknda.cse@ulab.edu.bd</a></div>
</div>
`.trim();

// ---------- helpers ----------
const escapeHtml = (str = '') =>
  String(str)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#39;');

// ---------- 5) Full text (Telegram preview) ----------
const fullText =
  `${salutation}\n\n` +
  `${draftBody}\n\n` +
  `${closing}\n` +
  `Md. Rifat Aknda`;

// ---------- 6) HTML body (for Gmail reply/send) ----------
const bodyHtml =
  `<div>${escapeHtml(salutation)}</div><br/>` +
  `<div>${escapeHtml(draftBody).replaceAll('\n', '<br/>')}</div><br/>` +
  `<div>${escapeHtml(closing)}<br/>Md. Rifat Aknda</div><br/>` +
  signatureHtml;

// ---------- 7) Subject normalize ----------
const originalSubject = s(item.email?.subject).trim();
let subject = s(o.subject).trim();

if (!subject) {
  if (originalSubject) {
    subject = originalSubject.toLowerCase().startsWith('re:')
      ? originalSubject
      : `Re: ${originalSubject}`;
  } else {
    subject = 'Re:';
  }
}

// ---------- 8) Always approval ----------
const needs_user_approval = true;

// ---------- 9) Telegram text + callback payloads ----------
const emailId = s(item.messageId || item.email?.id).trim() || 'noid';
const threadId = s(item.threadId || item.email?.threadId).trim() || 'nothread';
const mkCb = (action) => `${action}|${emailId}|${threadId}`;


const readabilityScore = item.output?.readability?.score ?? 'N/A';
const readabilityThreshold = item.output?.readability?.threshold ?? 'N/A';

const telegramText =
`📝 Email Reply Review

From: ${s(item.email?.fromName)} <${s(item.email?.fromEmail)}>
Subject: ${subject}

--- Proposed Reply ---

${fullText}

Readability: ${readabilityScore} (threshold ${readabilityThreshold})
Needs approval: YES`;

return [{
  json: {
    ...item,
    reply: {
      subject,
      salutation,
      closing,
      draft: draftBody,
      key_points: Array.isArray(o.key_points) ? o.key_points : [],
      questions: Array.isArray(o.questions) ? o.questions : [],
      confidence: typeof o.confidence === 'number' ? o.confidence : 0,
      needs_user_approval,
      fullText,
      bodyHtml,
      signatureHtml,
    },
    telegram: {
      text: telegramText,
      callbacks: {
        approve_send: mkCb('approve_send'),
        edit: mkCb('edit'),
        improve_more: mkCb('improve_more'),
        decline: mkCb('decline'),
      }
    },
  }
}];

const item = $input.item.json;

const cb = item.callback_query || {};
const data = String(cb.data || "");

// Expected: action|emailId|threadId
const [action = "", emailId = "", threadId = ""] = data.split("|");

return {
  action,
  emailId,
  threadId,
  telegram: {
    callbackQueryId: cb.id,
    chatId: cb.message?.chat?.id,
    messageId: cb.message?.message_id,
    fromUserId: cb.from?.id,
    data,
  },
  raw: item,
};
